// Parse struktur pesan dari Meta WhatsApp Business API
const body = $input.first().json;

// Handle Meta webhook verification (GET request)
if ($input.first().json['hub.mode']) {
  return [{ json: { isVerification: true, challenge: body['hub.challenge'] } }];
}

// Extract pesan
const entry = body?.entry?.[0];
const change = entry?.changes?.[0];
const value = change?.value;
const message = value?.messages?.[0];

if (!message) {
  return [{ json: { skip: true, reason: 'No message found' } }];
}

// Skip jika bukan text message
if (message.type !== 'text') {
  return [{ json: { skip: true, reason: 'Non-text message: ' + message.type } }];
}

const contact = value?.contacts?.[0];

return [{
  json: {
    skip: false,
    messageId: message.id,
    from: message.from, // nomor WA client (628xxx)
    clientName: contact?.profile?.name || 'Pelanggan',
    text: message.text.body,
    timestamp: message.timestamp,
    phoneNumberId: value.metadata.phone_number_id,
    waBusinessId: value.metadata.display_phone_number
  }
}];

