// Parse JSON response dari Groq HTTP API
// Response format: { choices: [{ message: { content: '...' } }] }
const groqResponse = $input.first().json;
const raw = groqResponse?.choices?.[0]?.message?.content || '';

let classification;
try {
  // Bersihkan markdown code block jika ada
  const cleaned = raw
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();
  classification = JSON.parse(cleaned);
} catch (e) {
  // Fallback jika parse gagal
  classification = {
    intent: 'OTHER',
    confidence: 0.5,
    extracted: {},
    needs_human: true,
    reason: 'Failed to parse AI response: ' + e.message
  };
}

// Ambil data pesan asli dari node sebelumnya
const messageData = $('Parse Meta Payload').first().json;

return [{
  json: {
    ...messageData,
    intent: classification.intent || 'OTHER',
    confidence: classification.confidence || 0.5,
    extracted: classification.extracted || {},
    needs_human: classification.needs_human || false,
    classifierReason: classification.reason || ''
  }
}];

// Balas greeting dengan sambutan
const name = $json.clientName || 'kak';
const firstName = name.split(' ')[0];

const replies = [
  `Halo ${firstName}, makasih udah hubungi Sudut Ruang!\n\nKita bantu desain arsitektur & interior buat rumah, cafe, kantor, villa, dan lainnya.\n\nAda yang bisa kita bantu? Ceritain dulu proyek yang lagi direncanain.`,
  `Hai ${firstName}! Selamat datang di Sudut Ruang.\n\nKita spesialis di jasa desain arsitektur & interior. Mau bangun atau renovasi apa nih?`,
];

// Random reply biar tidak monoton
const reply = replies[Math.floor(Math.random() * replies.length)];

return [{ json: { ...$json, replyText: reply } }];

// Kalau data lengkap (ada tipe + luas), langsung trigger estimator
// Kalau tidak lengkap, tanya info tambahan
const extracted = $json.extracted || {};
const hasType = !!extracted.building_type;
const hasArea = !!extracted.area_sqm;

let replyText;

if (hasType && hasArea) {
  // Data cukup, flag untuk trigger workflow estimator
  replyText = null; // akan di-handle oleh workflow 2
  return [{ json: { ...$json, triggerEstimator: true } }];
}

if (hasType && !hasArea) {
  replyText = `Oke, desain ${extracted.building_type} ya.\n\nBerapa luas areanya kak? (dalam m2)`;
} else if (!hasType && hasArea) {
  replyText = `Noted ${extracted.area_sqm}m2.\n\nIni rencananya untuk apa? Rumah tinggal, cafe, kantor, atau yang lain?`;
} else {
  replyText = `Boleh ceritain dulu proyeknya:\n1. Jenis bangunan (rumah/cafe/kantor/villa/renovasi)\n2. Luas area (m2)\n3. Kelas material (standar/menengah/premium)\n\nBiar kita bisa kasih estimasi yang akurat.`;
}

return [{ json: { ...$json, triggerEstimator: false, replyText } }];

// Balas request proposal
const name = $json.clientName || 'kak';
const firstName = name.split(' ')[0];

const replyText = `Siap ${firstName}, kita buatkan proposal lengkapnya.

Boleh konfirmasi dulu:
1. Nama lengkap
2. Jenis proyek & lokasi
3. Luas area (m2)
4. Budget range yang disiapkan

Proposal akan kita kirim dalam 1x24 jam.`;

return [{ json: { ...$json, replyText, triggerProposal: true } }];

// Notifikasi dashboard bahwa butuh human
const name = $json.clientName || 'Pelanggan';

return [{
  json: {
    ...$json,
    replyText: null, // Tidak auto-reply, tunggu human
    dashboardAlert: {
      priority: 'high',
      reason: $json.classifierReason || 'Needs human review',
      clientName: name,
      lastMessage: $json.text,
      conversationId: $json.from
    }
  }
}];
